keyframes_css:
@keyframes slide-left {
  0% { transform: translateX(0); }
  100% { transform: translateX(-100%); }
}

@keyframes slide-right {
  0% { transform: translateX(-100%); }
  100% { transform: translateX(0); }
}

.demo-stage {
  width: 200px;
  height: 200px;
  background: #87CEEB;
  overflow: hidden;
  position: relative;
}

.demo-stage::before {
  content: '';
  position: absolute;
  top: 0;
  left: 0;
  width: 200%;
  height: 40px;
  background: linear-gradient(90deg, #8B4513 0%, #A0522D 50%, #8B4513 100%);
  animation: slide-left 6s infinite;
}

.demo-stage::after {
  content: '';
  position: absolute;
  top: 40px;
  left: 0;
  width: 200%;
  height: 40px;
  background: linear-gradient(90deg, #D2B48C 0%, #DEB887 50%, #D2B48C 100%);
  animation: slide-right 5s infinite;
}

.layer-1 {
  position: absolute;
  top: 80px;
  left: 0;
  width: 200%;
  height: 40px;
  background: linear-gradient(90deg, #556B2F 0%, #6B8E23 50%, #556B2F 100%);
  animation: slide-left 7s infinite;
}

.layer-2 {
  position: absolute;
  top: 120px;
  left: 0;
  width: 200%;
  height: 40px;
  background: linear-gradient(90deg, #A9A9A9 0%, #C0C0C0 50%, #A9A9A9 100%);
  animation: slide-right 4s infinite;
}

.layer-3 {
  position: absolute;
  top: 160px;
  left: 0;
  width: 200%;
  height: 40px;
  background: linear-gradient(90deg, #696969 0%, #808080 50%, #696969 100%);
  animation: slide-left 8s infinite;
}

@keyframes slide-in {
  0% {
    transform: translateX(-100%);
    opacity: 0;
  }
  50% {
    opacity: 1;
  }
  100% {
    transform: translateX(0);
    opacity: 1;
  }
}

@keyframes settle {
  0% {
    transform: translateY(-20px);
    opacity: 0;
  }
  100% {
    transform: translateY(0);
    opacity: 1;
  }
}

.demo-stage {
  width: 200px;
  height: 200px;
  background: linear-gradient(180deg, #87ceeb 0%, #e0f6ff 100%);
  position: relative;
  overflow: hidden;
  border-radius: 8px;
}

.demo-stage .layer {
  position: absolute;
  width: 100%;
  height: 30px;
  left: 0;
}

.demo-stage .layer:nth-child(1) {
  top: 20px;
  background: linear-gradient(90deg, #d4a574 0%, #c19a6b 100%);
  animation: settle 0.8s ease-out 0s forwards;
}

.demo-stage .layer:nth-child(2) {
  top: 50px;
  background: linear-gradient(90deg, #8b7355 0%, #704214 100%);
  animation: settle 0.8s ease-out 0.3s forwards;
}

.demo-stage .layer:nth-child(3) {
  top: 80px;
  background: linear-gradient(90deg, #a0826d 0%, #6f4e37 100%);
  animation: settle 0.8s ease-out 0.6s forwards;
}

.demo-stage .layer:nth-child(4) {
  top: 110px;
  background: linear-gradient(90deg, #7c6b5d 0%, #5a4a42 100%);
  animation: settle 0.8s ease-out 0.9s forwards;
}

.demo-stage .layer:nth-child(5) {
  top: 140px;
  background: linear-gradient(90deg, #6b5b4f 0%, #3c3736 100%);
  animation: settle 0.8s ease-out 1.2s forwards;
}

.demo-stage .layer:nth-child(6) {
  top: 170px;
  background: linear-gradient(90deg, #4a4a4a 0%, #1a1a1a 100%);
  animation: settle 0.8s ease-out 1.5s forwards;
  animation-iteration-count: infinite;
  animation-delay: 4s;
}

.demo-stage .layer:nth-child(1) {
  animation: settle 0.8s ease-out 0s infinite;
  animation-delay: 0s;
}

.demo-stage .layer:nth-child(2) {
  animation: settle 0.8s ease-out 0.3s infinite;
  animation-delay: 0.3s;
}

.demo-stage .layer:nth-child(3) {
  animation: settle 0.8s ease-out 0.6s infinite;
  animation-delay: 0.6s;
}

.demo-stage .layer:nth-child(4) {
  animation: settle 0.8s ease-out 0.9s infinite;
  animation-delay: 0.9s;
}

.demo-stage .layer:nth-child(5) {
  animation: settle 0.8s ease-out 1.2s infinite;
  animation-delay: 1.2s;
}

.demo-stage .layer:nth-child(6) {
  animation: settle 0.8s ease-out 1.5s infinite;
  animation-delay: 1.5s;
}
